import React, { useContext } from 'react';
import { Container } from 'react-bootstrap'; 
// Solo mantenemos SettingsContext para el nombre y el color del fondo
import { SettingsContext } from '../context/SettingsContext'; 

// Todos los demás imports (Link, Dropdown, SearchBox, AuthContext, CartContext) han sido eliminados.

const Header = () => {
  const { settings } = useContext(SettingsContext);

  // Estilo minimalista para el texto
  const textClasses = "text-white text-lg font-bold";

  return (
    // CRÍTICO: Aquí están las clases de estilo. 
    // Si el redondeo no aparece, el problema es esta línea.
    <header 
      className="w-full sticky top-0 z-50 shadow-md rounded-b-xl"
      // Aseguramos el color oscuro usando la variable CSS.
      style={{ backgroundColor: 'var(--brand-dark)', minHeight: '70px' }} 
    >
      <Container className="py-3"> 
        <div className="d-flex justify-content-between align-items-center" style={{ height: '40px' }}> 
          
          {/* 1. Logo / Nombre del Sitio */}
          <span className={textClasses}>
            {settings?.siteName || 'TECNOTITLÁN'}
          </span>

          {/* 2. Placeholder del Buscador (Mantenemos el espacio) */}
          <div className="d-none d-lg-block w-1/2 max-w-lg mx-auto px-5">
            <div className="h-10 bg-white/20 rounded-full"></div>
          </div>

          {/* 3. Placeholder de Navegación Derecha */}
          <nav className="d-flex align-items-center gap-4">
             <span className={textClasses}>ACCIONES</span>
          </nav>
        </div>
      </Container>
    </header>
  );
};

export default Header;
